-      // Both backends fetch the same `onnx/model_q4f16.onnx` from
-      // `modelSource`. First run hits HF Hub; second run is served
-      // from the browser's HTTP cache.
-      import { PrivacyFilter } from "/packages/textsift/dist/index.js";
+      // Original/baseline = `transformers.js` running the same
+      // openai/privacy-filter ONNX. Forced via createWithResolver so the
+      // umbrella's auto-WebGPU short-circuit doesn't replace tjs with
+      // our WebGPU backend on machines that have one.
+      import { PrivacyFilter, TransformersJsBackend } from "/packages/textsift/dist/index.js";
+
+      const FORCE_TJS_RESOLVER = {
+        async resolveAuto({ bundle, quantization }) {
+          return new TransformersJsBackend({
+            bundle,
+            quantization,
+            device: "auto",
+          });
+        },
+      };
+      const createTjs = (opts = {}) =>
+        PrivacyFilter.createWithResolver(opts, FORCE_TJS_RESOLVER);

